import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { addDoc } from "../../api/documentApi";
import api from "../../api/axios";

export default function AddDocument() {
  const navigate = useNavigate();

  const [vehicles, setVehicles] = useState([]);
  const [users, setUsers] = useState([]); // holders
  const [loading, setLoading] = useState(false);

  const [form, setForm] = useState({
    title: "",
    docType: "RC_BOOK",
    referenceNo: "",
    vehicle: "",
    status: "AVAILABLE",
    location: "",
    holder: "",
    notes: "",
  });

  // ✅ adjust if your vehicle schema uses different field name
  const getVehicleNumber = (v) =>
    v?.vehicleNumber || v?.vehicle_number || v?.registrationNo || v?.regNo || "";

  useEffect(() => {
    const load = async () => {
      try {
        setLoading(true);

        const [vRes, uRes] = await Promise.all([
          api.get("/vehicles"),
          api.get("/users"), // ⚠️ change to your actual users route if needed
        ]);

        setVehicles(vRes.data || []);
        setUsers((uRes.data || []).filter((u) => !u.isDeleted)); // only active
      } catch (err) {
        console.error(err);
        // If users endpoint doesn't exist, you can still add docs without holder
        alert(err.response?.data?.message || "Failed to load vehicles/users");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, []);

  const submit = async (e) => {
    e.preventDefault();

    try {
      await addDoc({
        title: form.title,
        docType: form.docType,
        referenceNo: form.referenceNo,
        status: form.status,
        location: form.location,
        notes: form.notes,

        // ✅ optional fields
        vehicle: form.vehicle || undefined,
        holder: form.holder || undefined,
      });

      alert("Document added!");
      navigate("/documents");
    } catch (err) {
      alert(err.response?.data?.message || "Add failed");
    }
  };

  return (
    <div style={{ padding: 20, maxWidth: 560 }}>
      <h2>Add Physical Document</h2>

      {loading && <p>Loading dropdowns...</p>}

      <form onSubmit={submit}>
        <label>Title</label><br />
        <input
          value={form.title}
          onChange={(e) => setForm({ ...form, title: e.target.value })}
          style={{ width: "100%", padding: 10 }}
          required
        />

        <br /><br />

        <label>Type</label><br />
        <select
          value={form.docType}
          onChange={(e) => setForm({ ...form, docType: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="RC_BOOK">RC Book</option>
          <option value="INSURANCE">Insurance</option>
          <option value="TRANSFER_FORM">Transfer Form</option>
          <option value="EMISSION">Emission</option>
          <option value="SERVICE_BOOK">Service Book</option>
          <option value="OTHER">Other</option>
        </select>

        <br /><br />

        <label>Reference No (optional)</label><br />
        <input
          value={form.referenceNo}
          onChange={(e) => setForm({ ...form, referenceNo: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        />

        <br /><br />

        <label>Vehicle (optional)</label><br />
        <select
          value={form.vehicle}
          onChange={(e) => setForm({ ...form, vehicle: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="">-- none --</option>
          {vehicles.map((v) => {
            const vNum = getVehicleNumber(v);
            return (
              <option key={v._id} value={v._id}>
                {v.brand} {v.model || v.type || ""} ({v.year})
                {vNum ? ` - ${vNum}` : ""}
              </option>
            );
          })}
        </select>

        <br /><br />

        <label>Holder (optional)</label><br />
        <select
          value={form.holder}
          onChange={(e) => setForm({ ...form, holder: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="">-- none --</option>
          {users.map((u) => (
            <option key={u._id} value={u._id}>
              {u.name} ({u.role})
            </option>
          ))}
        </select>

        <br /><br />

        <label>Status</label><br />
        <select
          value={form.status}
          onChange={(e) => setForm({ ...form, status: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="AVAILABLE">AVAILABLE</option>
          <option value="IN_USE">IN_USE</option>
          <option value="MISSING">MISSING</option>
          <option value="ARCHIVED">ARCHIVED</option>
        </select>

        <br /><br />

        <label>Location</label><br />
        <input
          value={form.location}
          onChange={(e) => setForm({ ...form, location: e.target.value })}
          style={{ width: "100%", padding: 10 }}
          required
          placeholder="e.g., Office Cabinet A"
        />

        <br /><br />

        <label>Note</label><br />
        <textarea
          value={form.notes}
          onChange={(e) => setForm({ ...form, notes: e.target.value })}
          rows={3}
          style={{ width: "100%", padding: 10 }}
        />

        <br /><br />
        <button style={{ padding: "10px 14px" }}>Save</button>
      </form>
    </div>
  );
}
